import { useEffect, useRef } from 'react';
import { useIntl } from 'react-intl';

import { ExternalLinkIcon } from '@dynatrace/strato-icons';

import { Button } from '../../../../buttons/button/Button.js';
import { SEGMENTS_DOCUMENTATION_URL } from '../../../../core/external-links.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { Text } from '../../../../typography/text/Text.js';
import { SEGMENTSELECTOR_MESSAGES } from '../../segmentMessages.js';
import * as styles from '../Overlay.sty.js';
import { CopyPermissionsButton } from './CopyPermissionsButton.js';

/**
 * EmptyState-component for SegmentSelector Overlay without access rights to segments.
 * It shows a message that the user has no access to segments and a button to copy the permission details.
 * @internal
 */
export const NoAccessWithoutSelection = () => {
  const intl = useIntl();
  const buttonRef = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    // Focus the button when the component is mounted. Due to the possible loading
    // state, the overlay can't handle the focus as it tries it too early.
    buttonRef.current?.focus();
  }, []);

  return (
    <Flex
      flexDirection="column"
      alignItems="center"
      padding={16}
      width="100vw"
      className={styles.overlayDefaultWidth}
      style={{ maxWidth: '320px', textAlign: 'center' }}
    >
      <Text textStyle="base-emphasized">
        {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.noAccessNoSegments)}
      </Text>
      {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.copyDetailsHint)}
      <Flex>
        <CopyPermissionsButton variant="emphasized" ref={buttonRef} />
        <Button
          as="a"
          href={SEGMENTS_DOCUMENTATION_URL}
          target="_blank"
          rel="noopener noreferrer"
        >
          {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.docsLinkTextShort)}
          <Button.Suffix>
            <ExternalLinkIcon />
          </Button.Suffix>
        </Button>
      </Flex>
    </Flex>
  );
};
